#!/bin/bash
# init-coachtina.sh — Initialize CoachTinaMarie project structure
# Run after transcripts have been processed and wisdom extracted
# Timeline: 3-4 minutes to complete

set -e

WORKSPACE="/home/moriahkeeper/.openclaw/workspace"\nPROJECT="$WORKSPACE/coachtina-ai"\nTIMESTAMP=$(date '+%Y-%m-%d %H:%M:%S')\n\necho \"🏔️ Initializing CoachTinaMarie Project — $TIMESTAMP\"\necho \"\"\n\n# 1. Create project structure\necho \"[1/5] Creating project structure...\"\nmkdir -p \"$PROJECT\"/{src/{routes,middleware,services,types,utils,tests},public,docs}\ncd \"$PROJECT\"\n\n# 2. Initialize git & npm\necho \"[2/5] Initializing git and npm...\"\ngit init --quiet\nnpm init -y > /dev/null\n\n# 3. Install dependencies\necho \"[3/5] Installing dependencies (this may take a minute)...\"\nnpm install --silent \\\\\n  express typescript ts-node @types/express @types/node \\\\\n  sqlite3 better-sqlite3 @types/better-sqlite3 \\\\\n  dotenv jsonwebtoken @types/jsonwebtoken \\\\\n  bcrypt @types/bcrypt \\\\\n  zod axios \\\\\n  pino pino-pretty \\\\\n  jest @types/jest ts-jest supertest @types/supertest \\\\\n  cors uuid\n\n# 4. Create TypeScript config\necho \"[4/5] Creating TypeScript & build configuration...\"\ncat > tsconfig.json << 'EOF'\n{\n  \"compilerOptions\": {\n    \"target\": \"ES2020\",\n    \"module\": \"commonjs\",\n    \"lib\": [\"ES2020\"],\n    \"outDir\": \"./dist\",\n    \"rootDir\": \"./src\",\n    \"strict\": true,\n    \"esModuleInterop\": true,\n    \"skipLibCheck\": true,\n    \"forceConsistentCasingInFileNames\": true,\n    \"resolveJsonModule\": true\n  },\n  \"include\": [\"src/**/*\"],\n  \"exclude\": [\"node_modules\", \"dist\", \"**/*.test.ts\"]\n}\nEOF\n\ncat > package.json.new << 'EOF'\n{\n  \"name\": \"coachtina-ai\",\n  \"version\": \"1.0.0\",\n  \"description\": \"AI Coach powered by Tina's wisdom\",\n  \"main\": \"dist/index.js\",\n  \"scripts\": {\n    \"start\": \"ts-node src/index.ts\",\n    \"build\": \"tsc\",\n    \"test\": \"jest\",\n    \"test:watch\": \"jest --watch\",\n    \"dev\": \"ts-node --transpile-only src/index.ts\"\n  },\n  \"engines\": {\n    \"node\": \">=22.0.0\"\n  },\n  \"keywords\": [\"ai\", \"coach\", \"tina\", \"wisdom\"],\n  \"author\": \"Moriah\",\n  \"license\": \"ISC\"\n}\nEOF\n\nmv package.json.new package.json\n\ncat > .env.example << 'EOF'\n# Claude API\nANTHROPIC_API_KEY=sk-ant-...\n\n# Database\nDATABASE_PATH=./data/coachtina.db\n\n# Server\nPORT=3002\nNODE_ENV=development\n\n# Auth\nJWT_SECRET=your-secret-key-change-in-production\nJWT_EXPIRATION=7d\n\n# Integrations\nSKOOL_API_KEY=skool_...\nSTRIPE_API_KEY=sk_test_...\nVERCEL_KV_URL=redis://...\n\n# Logging\nLOG_LEVEL=info\nEOF\n\n# 5. Create README\necho \"[5/5] Creating documentation...\"\ncat > README.md << 'EOF'\n# CoachTinaMarie\n\nAI Coach powered by 23 years of Tina's wisdom.\n\n## Quick Start\n\n```bash\ncp .env.example .env\n# Edit .env with your API keys\nnpm run dev\n```\n\nServer runs on http://localhost:3002\n\n## Architecture\n\nSee `/docs/ARCHITECTURE.md` (generated from parent COACHTINA_ARCHITECTURE_PLAN.md)\n\n## Build Timeline\n\n- Hour 1: Foundation (auth, database, basic routes)\n- Hour 2: Core coaching (chat endpoint, Claude integration)\n- Hour 3: Enhancement (progress tracking, feedback)\n- Hour 4: Integration (Skool, revenue metering)\n- Hour 5: Polish (tests, docs, deployment)\n\n## Testing\n\n```bash\nnpm test\n```\n\n## Deployment\n\nVercel deployment ready:\n\n```bash\nvercel\n```\nEOF\n\n# 6. Create .gitignore\ncat > .gitignore << 'EOF'\nnode_modules/\ndist/\n.env\n.env.local\n*.log\n.DS_Store\ndata/*.db\ndata/*.db-*\ncoverage/\n.vercel/\nEOF\n\n# 7. Initialize git\ngit add .\ngit commit -m \"CoachTinaMarie: Project initialization\" --quiet 2>/dev/null || true\n\necho \"\"\necho \"✅ CoachTinaMarie Project Ready\"\necho \"\"\necho \"Next steps:\"\necho \"  1. cp .env.example .env\"\necho \"  2. Add ANTHROPIC_API_KEY to .env\"\necho \"  3. npm run dev\"\necho \"\"\necho \"Project location: $PROJECT\"\necho \"Ready for Phase 1 implementation (src/)\"\necho \"\"\n"